import os


def delete_uploaded_file(filename: str) -> bool:
    """
    Delete a user's uploaded file from the 'uploads' directory based on the filename.
    
    Prevents path traversal attacks by ensuring the resolved file path
    is within the uploads directory.
    
    Args:
        filename: The name of the file to delete.
        
    Returns:
        True if the file was successfully deleted, False otherwise.
        
    Raises:
        ValueError: If the filename is invalid or attempts path traversal.
        FileNotFoundError: If the file does not exist in the uploads directory.
    """
    if not filename or not isinstance(filename, str):
        raise ValueError("Filename must be a non-empty string.")
    
    # Define the uploads directory using an absolute path
    uploads_dir = os.path.abspath("uploads")
    
    # Construct the full file path and resolve it to an absolute path
    requested_path = os.path.abspath(os.path.join(uploads_dir, filename))
    
    # Prevent path traversal: ensure the resolved path is within the uploads directory
    # Use os.sep to ensure we're checking for a proper directory prefix
    if not requested_path.startswith(uploads_dir + os.sep) and requested_path != uploads_dir:
        raise ValueError("Invalid filename: path traversal is not allowed.")
    
    # Additional check: ensure the filename doesn't contain directory separators
    # This prevents accessing subdirectories even within uploads
    basename = os.path.basename(filename)
    if basename != filename:
        raise ValueError("Invalid filename: directory separators are not allowed.")
    
    # Check that the resolved path matches what we expect with the basename
    expected_path = os.path.join(uploads_dir, basename)
    if requested_path != os.path.abspath(expected_path):
        raise ValueError("Invalid filename: path traversal is not allowed.")
    
    # Check if the file exists
    if not os.path.exists(requested_path):
        raise FileNotFoundError(f"File '{basename}' not found in uploads directory.")
    
    # Ensure it's a file and not a directory or symlink
    if os.path.islink(requested_path):
        raise ValueError("Invalid filename: symbolic links are not allowed.")
    
    if not os.path.isfile(requested_path):
        raise ValueError("Invalid filename: the specified path is not a regular file.")
    
    # Delete the file
    os.remove(requested_path)
    return True


